+    let mut resolver = DeterministicModuleResolver::new("/repo");
+    resolver
+        .register_external_package(ExternalPackageDefinition::new("locked-pkg").with_export(
+            ".",
+            export_target(&[("default", "../other-pkg/private.js")], None),
+        ))
+        .unwrap();
